function defaultTrip(){return normalizeTrip({id:uid('trip'),templateKey:'fukuoka-classic-v1',brandLine:'TINO FAMILY TRIP В· FUKUOKA',title:'зҰҸеІЎдёүд»ЈеҗҢе Ӯ\nз¶“е…ёз©©е®ҡзүҲ',subtitle:'5 еӨ§ 1 е°ҸпҪңеҺҹи·Ҝз·ҡеҫ®иӘҝпҪңйӨҗе»ій Ҷи·ҜеҠ е…Ҙ',members:'TinoгҖҒжҪҳе©·гҖҒзҲёзҲёгҖҒеӘҪеӘҪгҖҒеІіжҜҚгҖҒеҳҹеҳҹпјҲ3 жӯІпјү',city:'зҰҸеІЎ',dateRange:'8/20вҖ“8/26',startDate:'2026-08-20',hotel:'дёүдә•иҠұең’йЈҜеә—зҰҸеІЎдёӯжҙІ',nights:'6 жҷҡеҗҢйЈҜеә—',tags:'й•·иј©еҸҜдј‘, жҺЁи»Ҡе„Әе…Ҳ, йӣЁеӨ©еӮҷжЎҲ',themeColor:'#173f73',days:clone(window.DEFAULT_ITINERARY||[]),progress:{},currentDayId:localStorage.getItem(LEGACY_DAY_KEY)||1});}
