function upgradeClassicTrip(t){if(!t||t.templateKey==='fukuoka-comfort-v1'||t.city!=='зҰҸеІЎ'||t.days.length!==7)return false;const isClassic=t.templateKey==='fukuoka-classic-v1'||t.title.includes('зҰҸеІЎдёүд»ЈеҗҢе Ӯ');if(!isClassic)return false;const defaults=window.DEFAULT_ITINERARY||[],day1=t.days[0],day2=t.days[1],day4=t.days[3];const copyStop=name=>{for(const d of defaults){const found=d.stops.find(s=>s.name===name);if(found)return normalizeStop(clone(found),0);}return null;};if(day1&&!day1.stops.some(s=>s.name==='THE FULL FULL HAKATA')){const stop=copyStop('THE FULL FULL HAKATA'),index=day1.stops.findIndex(s=>s.name==='ж«ӣз”°зҘһзӨҫ');if(stop)day1.stops.splice(index<0?day1.stops.length:index,0,stop);}const oldDinner=day2?.stops.find(s=>s.name==='еҚҡеӨҡз«ҷжҷҡйӨҗ A/B');const newDinner=copyStop('еҚҡеӨҡгӮӮгҒӨйҚӢ еүҚз”°еұӢ еҚҡеӨҡеә—');if(oldDinner&&newDinner)Object.assign(oldDinner,{...newDinner,id:oldDinner.id});if(day4&&!day4.stops.some(s=>s.name==='Pain Stock еӨ©зҘһеә—')){const stop=copyStop('Pain Stock еӨ©зҘһеә—');if(stop)day4.stops.unshift(stop);}const oldCafe=day4?.stops.find(s=>s.name==='Royal Garden Cafe Ohori Park');const daidai=copyStop('еҚҡеӨҡж°ҙзӮҠгҒҚе°Ҳй–Җ ж©ҷ');if(oldCafe&&daidai)Object.assign(oldCafe,{...daidai,id:oldCafe.id});t.templateKey='fukuoka-classic-v1';if(t.title.includes('з„ЎзӨҷеӢ•з·ҡ'))t.title='зҰҸеІЎдёүд»ЈеҗҢе Ӯ\nз¶“е…ёз©©е®ҡзүҲ';t.subtitle='5 еӨ§ 1 е°ҸпҪңеҺҹи·Ҝз·ҡеҫ®иӘҝпҪңйӨҗе»ій Ҷи·ҜеҠ е…Ҙ';return true;}
function ensureRoutePlans(value){const data=normalizeAppData(value);if(localStorage.getItem(ROUTE_PLANS_DONE)==='true')return data;const current=data.trips.find(t=>t.id===data.currentTripId),classic=[current,...data.trips].find((t,i,a)=>t&&a.indexOf(t)===i&&t.city==='зҰҸеІЎ'&&t.days.length===7&&(t.templateKey==='fukuoka-classic-v1'||t.title.includes('зҰҸеІЎдёүд»ЈеҗҢе Ӯ')));upgradeClassicTrip(classic);if(!data.trips.some(t=>t.templateKey==='fukuoka-comfort-v1'||t.id==='fukuoka-comfort-route-v1'))data.trips.push(routePlanTwoTrip());localStorage.setItem(ROUTE_PLANS_DONE,'true');localStorage.setItem(APP_KEY,JSON.stringify(data));return data;}
function migrateLegacy(){if(localStorage.getItem(LEGACY_DONE)==='true')return null;const legacy=safeJson(localStorage.getItem(LEGACY_ITINERARY_KEY),null), progress=safeJson(localStorage.getItem(LEGACY_PROGRESS_KEY),{});const trip=defaultTrip(); if(legacy)trip.days=legacy.map(normalizeDay); trip.progress=Object.fromEntries(Object.entries(progress||{}).map(([k,v])=>[k.split(':').length===2?`${trip.id}:${k}`:k,v])); trip.currentDayId=String(localStorage.getItem(LEGACY_DAY_KEY)||trip.days[0]?.id); localStorage.setItem(LEGACY_DONE,'true'); return {schemaVersion:SCHEMA_VERSION,currentTripId:trip.id,trips:[trip]};}
