function setAppStatus(text,tone='saved',delay=1800){const el=$('appStatus');if(!el)return;el.textContent=text;el.dataset.tone=tone;clearTimeout(setAppStatus.timer);if(delay)setAppStatus.timer=setTimeout(()=>{if(navigator.onLine){el.textContent='вң“ е·Іе„Іеӯҳ';el.dataset.tone='saved';}},delay);}function save(){try{localStorage.setItem(APP_KEY,JSON.stringify(appData));setAppStatus('вң“ е·Іе„Іеӯҳ','saved');return true;}catch{setAppStatus('е„Іеӯҳз©әй–“дёҚи¶і','error',0);alert('иЈқзҪ®е„Іеӯҳз©әй–“дёҚи¶іпјҢи«ӢжҸӣдёҖејөијғе°Ҹзҡ„з…§зүҮжҲ–е…ҲеҢҜеҮәеӮҷд»ҪгҖӮ');return false;}}
