function renderHero(){const t=trip();document.documentElement.style.setProperty('--navy',t.themeColor||'#173f73');$('brandLine').textContent=t.brandLine;$('heroTitle').innerHTML=esc(t.title).replace(/\n/g,'<br>');$('heroSubtitle').textContent=t.subtitle;$('tripFacts').innerHTML=[t.dateRange,t.nights,t.city].filter(Boolean).map(x=>`<span>${esc(x)}</span>`).join('');$('tripSelect').innerHTML=appData.trips.map(x=>`<option value="${esc(x.id)}" ${x.id===t.id?'selected':''}>${esc(x.title.replace(/\n/g,' '))}</option>`).join('');}
