function renderMapTabs(){const t=trip(),current=day(),allCount=t.days.reduce((n,d)=>n+d.stops.filter(hasCoord).length,0),status=$('mapStatus');$('mapDayTabs').innerHTML=t.days.map((d,i)=>`<button class="map-day-tab ${!showAllMap&&d.id===current.id?'active':''}" data-map-day="${esc(d.id)}" style="--day-color:${MAP_COLORS[i%MAP_COLORS.length]}"><i></i><b>Day ${i+1}</b><small>${esc((d.date||'').split(' ')[0])}</small></button>`).join('');$('fitMap').classList.toggle('active',showAllMap);$('fitMap').disabled=allCount===0;$('fitMap').textContent=showAllMap?'е…ЁйғЁиЎҢзЁӢ':'йЎҜзӨәе…ЁйғЁ';$('openDayMap').textContent=`Day ${t.days.indexOf(current)+1} Maps`;$('openDayMap').href=dayRouteUrl(current);const shown=showAllMap?allCount:current.stops.filter(hasCoord).length;if(status){status.hidden=shown>0;status.textContent=showAllMap?'ж•ҙи¶ҹж—…иЎҢе°ҡз„ЎеҸҜйЎҜзӨәзҡ„жҷҜй»һеә§жЁҷгҖӮ':`Day ${t.days.indexOf(current)+1} е°ҡз„ЎеҸҜйЎҜзӨәзҡ„жҷҜй»һеә§жЁҷгҖӮ`;}document.querySelectorAll('[data-map-day]').forEach(button=>button.onclick=()=>{t.currentDayId=button.dataset.mapDay;showAllMap=false;save();renderTabs();renderDay();renderMapTabs();});}
function tripExpense(t=trip()){return t.days.reduce((sum,d)=>sum+d.stops.reduce((n,s)=>n+num(s.expense),0),0);}function dayExpense(d=day()){return (d?.stops||[]).reduce((sum,s)=>sum+num(s.expense),0);}const yen=value=>new Intl.NumberFormat('zh-TW',{style:'currency',currency:'JPY',maximumFractionDigits:0}).format(num(value));
function tripStats(t){return {days:t.days.length,stops:t.days.reduce((n,d)=>n+d.stops.length,0),expense:tripExpense(t)};}
function tripPhase(t){if(!/^\d{4}-\d{2}-\d{2}$/.test(t.startDate||''))return {tone:'planning',label:'зӯүеҫ…иЁӯе®ҡж—…иЎҢж—Ҙжңҹ'};const start=new Date(`${t.startDate}T00:00:00`),today=new Date();today.setHours(0,0,0,0);const end=new Date(start);end.setDate(end.getDate()+Math.max(0,t.days.length-1));const diff=Math.round((start-today)/86400000);if(today<start)return {tone:'upcoming',label:diff===1?'жҳҺеӨ©еҮәзҷј':`и·қйӣўеҮәзҷј ${diff} еӨ©`};if(today<=end)return {tone:'active',label:`ж—…йҖ”дёӯ В· Day ${Math.floor((today-start)/86400000)+1}`};return {tone:'past',label:'ж—…зЁӢеӣһйЎ§'};}
function memoryCard(t,current=false){const stats=tripStats(t),phase=tripPhase(t),photo=t.coverPhoto?`<img src="${esc(t.coverPhoto)}" alt="${esc(t.title.replace(/\n/g,' '))}зҡ„ж—…иЎҢз…§зүҮ">`:'<div class="memory-placeholder"><span>вңҰ</span><b>з•ҷдёӢйҖҷи¶ҹж—…зЁӢжңҖйҮҚиҰҒзҡ„дёҖејөз…§зүҮ</b></div>';return `<article class="memory-card ${current?'featured':''}" ${current?'':`data-memory-trip="${esc(t.id)}"`}><div class="memory-photo">${photo}<div class="memory-shade"></div><span class="memory-phase ${phase.tone}">${esc(phase.label)}</span><div class="memory-caption"><p>${esc(t.city||'ж—…иЎҢ')}</p><h2>${esc(t.title.replace(/\n/g,' '))}</h2></div></div><div class="memory-stats"><span><b>${stats.days}</b> еӨ©</span><span><b>${stats.stops}</b> еҖӢжҷҜй»һ</span><span><b>${yen(stats.expense)}</b> зёҪиҠұиІ»</span></div>${current?`<div class="memory-actions"><button id="chooseCoverPhoto" type="button">${t.coverPhoto?'жӣҙжҸӣз…§зүҮ':'пјӢ йҒёж“ҮйҮҚиҰҒз…§зүҮ'}</button>${t.coverPhoto?'<button id="removeCoverPhoto" class="danger" type="button">з§»йҷӨз…§зүҮ</button>':''}${appData.trips.length>1?'<button id="deleteCurrentTrip" class="danger" type="button">еҲӘйҷӨжӯӨж—…зЁӢ</button>':''}</div>`:''}</article>`;}
function backupDue(){return !lastBackupAt||Date.now()-lastBackupAt>14*86400000;}function backupLabel(){if(!lastBackupAt)return 'е°ҡжңӘе»әз«Ӣе®Ңж•ҙеӮҷд»Ҫ';return `дёҠж¬Ўе®Ңж•ҙеӮҷд»Ҫпјҡ${new Date(lastBackupAt).toLocaleDateString('zh-TW')}`;}
function renderHome(){const t=trip(),others=appData.trips.filter(x=>x.id!==t.id),backup=backupDue()?`<div class="backup-nudge"><div><b>ж—…иЎҢиіҮж–ҷиЁҳеҫ—еӮҷд»Ҫ</b><span>${esc(backupLabel())}пјҢз…§зүҮд№ҹжңғдёҖиө·дҝқеӯҳгҖӮ</span></div><button id="quickBackup" type="button">з«ӢеҚіеӮҷд»Ҫ</button></div>`:'';$('homePanel').innerHTML=`<div class="memory-overview">${memoryCard(t,true)}${backup}${others.length?`<section class="past-trips"><div class="memory-section-title"><h2>е…¶д»–ж—…зЁӢ</h2><span>${others.length} и¶ҹ</span></div><div class="memory-strip">${others.map(x=>memoryCard(x)).join('')}</div></section>`:''}</div>`;$('chooseCoverPhoto')?.addEventListener('click',()=>$('coverPhotoInput').click());$('removeCoverPhoto')?.addEventListener('click',()=>{if(confirm('з§»йҷӨйҖҷејөж—…иЎҢз…§зүҮпјҹ')){t.coverPhoto='';save();renderHome();}});$('deleteCurrentTrip')?.addEventListener('click',deleteTrip);$('quickBackup')?.addEventListener('click',performFullBackup);document.querySelectorAll('[data-memory-trip]').forEach(card=>card.onclick=()=>{appData.currentTripId=card.dataset.memoryTrip;save();renderAll();document.querySelector('.app-shell>main')?.scrollTo({top:0,behavior:'auto'});});}
function sortDay(d){if(d.autoSort)d.stops=stableTimeSort(d.stops);}
function renderDay(){const t=trip(),d=day();if(!d)return;sortDay(d);$('daySummary').innerHTML=`<article class="summary-card journey-summary"><div class="journey-heading"><p class="date-line">${esc(d.date)} В· DAY ${t.days.indexOf(d)+1}${d.area?` В· ${esc(d.area)}`:''}</p><h2>${esc(d.title)}</h2></div><div class="weather-row" id="dayWeather"><span>рҹҢӨ еӨ©ж°Јијүе…ҘдёӯвҖҰ</span></div><div class="journey-footer"><div class="journey-metrics"><span>рҹ“Қ ${d.stops.length} з«ҷ</span><span>рҹ’ҙ ${yen(dayExpense(d))}</span></div><button class="share-day" id="shareDay" type="button">вҶ— еҲҶдә«д»Ҡж—Ҙ</button></div>${editMode?dayEditor(d,t):''}</article>`;$('timeline').innerHTML=d.stops.map((s,i)=>`${i?travelInfo(d.stops[i-1],s):''}${stopCard(d,s,i)}`).join('')+`<button class="add-stop-fixed" id="quickAddStop">пјӢ ж–°еўһжҷҜй»һ</button>`;bindEditors(d);$('openDayMap').href=dayRouteUrl(d);updateMap(d);}
function dayEditor(d,t){return `<div class="editor-panel day-editor"><label class="sort-toggle"><input type="checkbox" id="autoSort" ${d.autoSort!==false?'checked':''}>дҫқжҷӮй–“иҮӘеӢ•жҺ’еәҸ</label><label>ж—Ҙжңҹ<input data-day-field="date" value="${esc(d.date)}"></label><label>жҜҸж—Ҙдё»йЎҢ<input data-day-field="title" value="${esc(d.title)}"></label><label>еҚҖеҹҹ<input data-day-field="area" value="${esc(d.area)}"></label><label class="wide">иӘӘжҳҺ<textarea data-day-field="theme">${esc(d.theme)}</textarea></label><div class="edit-actions"><button class="edit-btn primary" id="addStop">пјӢж–°еўһжҷҜй»һ</button><button class="edit-btn" id="copyDay">иӨҮиЈҪжң¬ж—Ҙ</button><button class="edit-btn" id="dayUp">вҶ‘ ж—ҘжңҹдёҠз§»</button><button class="edit-btn" id="dayDown">вҶ“ ж—ҘжңҹдёӢз§»</button><button class="edit-btn danger" id="deleteDay">еҲӘйҷӨжң¬ж—Ҙ</button></div></div>`;}
function transportIcon(s){const v=`${s.transport||''} ${s.type||''}`;return v.includes('ең°йҗө')?'рҹҡҮ':v.includes('JR')?'рҹҡҶ':v.includes('е·ҙеЈ«')||v.includes('дәӨйҖҡ')?'рҹҡҢ':v.includes('еҢ…и»Ҡ')?'рҹҡҗ':v.includes('жҺҘйҖҒ')?'рҹҡҗ':'рҹҡ¶';}
function travelInfo(a,b){const km=haversineKm(a,b),distance=formatDistance(km),route=routeUrl(a,b);return route?`<a class="travel-info" href="${route}" target="_blank" rel="noopener">${transportIcon(b)} ${distance}${b.duration?`пҪңзҙ„ ${esc(b.duration)}`:''}<small>зӣҙз·ҡи·қйӣў В· й–Ӣе•ҹ Google Maps</small></a>`:`<div class="travel-info unavailable">${transportIcon(b)} ${distance}<small>зӣҙз·ҡи·қйӣў</small></div>`;}
function stopCard(d,s,i){const done=trip().progress[pkey(d.id,s.id)],prev=d.stops[i-1];return `<article class="stop-card ${done?'done':''}" data-index="${i}" data-stop-id="${esc(s.id)}"><div class="stop-icon">${ICONS[s.type]||'вҖў'}</div><div class="stop-header"><div><div class="stop-time">${esc(s.time)} <span class="stop-type">пҪң${esc(s.type)}</span></div><h3 class="stop-name">${esc(s.name)}</h3></div><button class="complete" data-complete="${esc(s.id)}">вң“</button></div><p class="stop-note">${esc(s.note)}</p>${i?`<div class="travel-note">${esc(s.transport||'еҫһдёҠдёҖз«ҷеүҚеҫҖ')} ${s.duration?`В· ${esc(s.duration)}`:''}</div>`:''}<div class="badges"><span class="badge elder">й•·иј©пҪң${esc(s.elder)}</span><span class="badge kid">еҳҹеҳҹпҪң${esc(s.kid)}</span>${s.backup?`<span class="badge backup">еӮҷжЎҲпҪң${esc(s.backup)}</span>`:''}${num(s.expense)>0?`<span class="badge expense">еҜҰд»ҳпҪң${yen(s.expense)}</span>`:''}</div><div class="actions"><a class="action map" href="${searchUrl(s)}" target="_blank" rel="noopener">рҹ“Қ жҹҘзңӢең°й»һ</a>${prev&&routeUrl(prev,s)?`<a class="action route" href="${routeUrl(prev,s)}" target="_blank" rel="noopener">рҹ§ӯ еҫһдёҠдёҖз«ҷе°ҺиҲӘ</a>`:''}<button class="action quick-action" data-quick-edit type="button">вңҸпёҸ з·ЁијҜ</button><button class="action quick-action danger" data-quick-delete type="button">рҹ—‘пёҸ еҲӘйҷӨ</button></div>${editMode?stopEditor(s,i,d.stops.length):''}</article>`;}
function stopEditor(s,i,total){const input=(f,l)=>`<label>${l}<input ${f==='time'?'type="time"':''} data-stop-field="${f}" value="${esc(s[f])}"></label>`;return `<div class="editor-panel stop-editor">${input('time','жҷӮй–“')}${input('name','еҗҚзЁұ')}<label>йЎһеһӢ<input list="typeList" data-stop-field="type" value="${esc(s.type)}"></label>${input('transport','дәӨйҖҡ')}${input('duration','з§»еӢ•')}${input('expense','еҜҰйҡӣиҠұиІ»пјҲж—Ҙең“пјү')}${input('lat','з·ҜеәҰ')}${input('lng','з¶“еәҰ')}<label class="wide">иӘӘжҳҺ<textarea data-stop-field="note">${esc(s.note)}</textarea></label>${input('elder','й•·иј©')}${input('kid','е№је…’')}<label class="wide">еӮҷжЎҲ<input data-stop-field="backup" value="${esc(s.backup)}"></label><div class="edit-actions"><button class="edit-btn" data-copy-stop>иӨҮиЈҪ</button><button class="edit-btn" data-move="up" ${i===0?'disabled':''}>вҶ‘ дёҠз§»</button><button class="edit-btn" data-move="down" ${i===total-1?'disabled':''}>вҶ“ дёӢз§»</button><button class="edit-btn danger" data-delete-stop>еҲӘйҷӨ</button></div></div>`;}
function bindEditors(d){document.querySelectorAll('[data-complete]').forEach(b=>b.onclick=()=>{const k=pkey(d.id,b.dataset.complete);trip().progress[k]=!trip().progress[k];if(!trip().progress[k])delete trip().progress[k];save();renderDay();});$('quickAddStop').onclick=()=>openStopSheet();$('shareDay').onclick=shareCurrentDay;document.querySelectorAll('.stop-card').forEach(card=>{const s=d.stops[Number(card.dataset.index)];card.querySelector('[data-quick-edit]')?.addEventListener('click',()=>openStopSheet(s));card.querySelector('[data-quick-delete]')?.addEventListener('click',()=>{if(confirm(`еҲӘйҷӨгҖҢ${s.name}гҖҚпјҹ`))deleteStopWithUndo(d,s,Number(card.dataset.index));});});if(!editMode)return;document.querySelectorAll('[data-day-field]').forEach(el=>el.oninput=()=>{d[el.dataset.dayField]=el.value;save();renderHero();renderTabs();updateMap(d);});$('addStop').onclick=openStopSheet;$('autoSort').onchange=e=>{d.autoSort=e.target.checked;sortDay(d);save();renderDay();};$('copyDay').onclick=()=>{const c=clone(d);c.id=uid('day');c.stops=c.stops.map(s=>({...s,id:uid('stop')}));trip().days.splice(trip().days.indexOf(d)+1,0,c);trip().currentDayId=c.id;save();renderAll();};$('deleteDay').onclick=deleteDay;$('dayUp').onclick=()=>moveDay(-1);$('dayDown').onclick=()=>moveDay(1);document.querySelectorAll('.stop-card').forEach(card=>{const s=d.stops[Number(card.dataset.index)];card.querySelectorAll('[data-stop-field]').forEach(el=>el.onchange=()=>{s[el.dataset.stopField]=['lat','lng'].includes(el.dataset.stopField)?coordNum(el.value):el.dataset.stopField==='expense'?Math.max(0,Math.round(num(el.value))):el.value;save();renderDay();});card.querySelector('[data-copy-stop]')?.addEventListener('click',()=>{const c={...clone(s),id:uid('stop')};d.stops.splice(Number(card.dataset.index)+1,0,c);save();renderDay();});card.querySelector('[data-delete-stop]')?.addEventListener('click',()=>{deleteStopWithUndo(d,s,Number(card.dataset.index))});card.querySelectorAll('[data-move]').forEach(b=>b.onclick=()=>moveStop(Number(card.dataset.index),b.dataset.move));});}

function dayShareText(t=trip(),d=day()){const index=t.days.indexOf(d)+1,stops=d.stops.map(s=>`${s.time||'--:--'}гҖҖ${s.name}`).join('\n')||'д»ҠеӨ©е°ҡжңӘе®үжҺ’жҷҜй»һ';return `${t.title.replace(/\n/g,' ')}пҪңDay ${index}\n${d.date}${d.title?`гҖҖ${d.title}`:''}\n\n${stops}\n\nGoogle Maps и·Ҝз·ҡпјҡ${dayRouteUrl(d)}`;}
function copyShareText(text){if(navigator.clipboard?.writeText)return navigator.clipboard.writeText(text);const area=document.createElement('textarea');area.value=text;area.style.position='fixed';area.style.opacity='0';document.body.appendChild(area);area.select();document.execCommand('copy');area.remove();return Promise.resolve();}
async function shareCurrentDay(){const t=trip(),d=day(),text=dayShareText(t,d);try{if(navigator.share)await navigator.share({title:`${t.title.replace(/\n/g,' ')} Day ${t.days.indexOf(d)+1}`,text});else{await copyShareText(text);showNotice('д»Ҡж—ҘиЎҢзЁӢе·ІиӨҮиЈҪпјҢеҸҜд»ҘиІјеҲ° LINE жҲ–иЁҠжҒҜгҖӮ');}}catch(error){if(error.name!=='AbortError'){await copyShareText(text);showNotice('д»Ҡж—ҘиЎҢзЁӢе·ІиӨҮиЈҪпјҢеҸҜд»ҘиІјеҲ° LINE жҲ–иЁҠжҒҜгҖӮ');}}}
function renderSettings(){const t=trip(),field=(f,l)=>`<label>${l}<input data-trip-field="${f}" value="${esc(t[f])}"></label>`;$('settingsPanel').innerHTML=`<div class="backup-status ${backupDue()?'due':'safe'}"><div><b>${backupDue()?'иіҮж–ҷе°ҡжңӘе®үе…ЁеӮҷд»Ҫ':'иіҮж–ҷе·ІжңүеӮҷд»Ҫ'}</b><span>${esc(backupLabel())}</span></div><button id="backupAll" type="button">${backupDue()?'з«ӢеҚіе®Ңж•ҙеӮҷд»Ҫ':'еҶҚж¬ЎеӮҷд»Ҫ'}</button></div><div class="editor-panel settings-editor">${field('brandLine','е“ҒзүҢеҲ—')}<label>дё»йЎҢйЎҸиүІ<input type="color" data-trip-field="themeColor" value="${esc(t.themeColor)}"></label><label class="wide">дё»жЁҷйЎҢ<textarea data-trip-field="title">${esc(t.title)}</textarea></label>${field('subtitle','еүҜжЁҷйЎҢ')}${field('members','жҲҗе“Ўж‘ҳиҰҒ')}${field('city','еҹҺеёӮ')}${field('dateRange','ж—Ҙжңҹ')}${field('startDate','ж—…иЎҢй–Ӣе§Ӣж—ҘпјҲYYYY-MM-DDпјү')}${field('hotel','йЈҜеә—')}${field('nights','дҪҸе®ҝжҷҡж•ё')}${field('tags','жЁҷзұӨ')}<div class="edit-actions"><button class="edit-btn danger" id="deleteTrip">еҲӘйҷӨж—…иЎҢ</button></div></div><div class="data-tools"><button class="reset-button primary" id="exportTrip">еҢҜеҮәе–®дёҖж—…иЎҢ</button><button class="reset-button primary" id="importTrip">еҢҜе…Ҙе–®дёҖж—…иЎҢ</button><button class="reset-button primary" id="restoreBackup">е®Ңж•ҙйӮ„еҺҹ</button><button class="reset-button" id="restoreDefault">жҒўеҫ©еҺҹе§ӢзҰҸеІЎиЎҢзЁӢ</button><button class="reset-button" id="resetProgress">жё…йҷӨжң¬ж—…иЎҢе®ҢжҲҗзҙҖйҢ„</button></div>`;document.querySelectorAll('[data-trip-field]').forEach(el=>el.oninput=()=>{t[el.dataset.tripField]=el.value;save();renderHero();renderHome();});$('deleteTrip').onclick=deleteTrip;$('exportTrip').onclick=()=>downloadJson(`${t.city||'trip'}-v4.json`,t);$('backupAll').onclick=performFullBackup;$('importTrip').onclick=()=>$('importFile').click();$('restoreBackup').onclick=()=>$('restoreFile').click();$('restoreDefault').onclick=()=>{if(confirm('жҒўеҫ©еҺҹе§ӢзҰҸеІЎиЎҢзЁӢпјҹ')){const n=defaultTrip();Object.assign(t,n,{id:t.id,progress:{}});save();renderAll();}};$('resetProgress').onclick=()=>{if(confirm('жё…йҷӨжң¬ж—…иЎҢе®ҢжҲҗзҙҖйҢ„пјҹ')){t.progress={};save();renderAll(true);}};}
function addDay(){const t=trip(),d=normalizeDay({id:uid('day'),date:'ж–°ж—Ҙжңҹ',title:'ж–°иЎҢзЁӢж—Ҙ',theme:'и«Ӣијёе…Ҙд»Ҡж—Ҙдё»йЎҢгҖӮ',stops:[]},t.days.length);t.days.push(d);t.currentDayId=d.id;save();renderAll();}
function moveDay(delta){const t=trip(),i=t.days.indexOf(day()),to=i+delta;if(to<0||to>=t.days.length)return;[t.days[i],t.days[to]]=[t.days[to],t.days[i]];save();renderAll();}
function deleteDay(){const t=trip(),d=day();if(t.days.length<=1)return alert('иҮіе°‘йңҖдҝқз•ҷдёҖеӨ©гҖӮ');if(confirm('еҲӘйҷӨжң¬ж—ҘиҲҮжүҖжңүжҷҜй»һпјҹ')){t.days=t.days.filter(x=>x!==d);t.currentDayId=t.days[0].id;save();renderAll();}}
function moveStop(i,dir){const d=day(),to=dir==='up'?i-1:i+1;if(to<0||to>=d.stops.length)return;d.autoSort=false;[d.stops[i],d.stops[to]]=[d.stops[to],d.stops[i]];save();renderDay();}
function parseGoogleMapsUrl(raw){const value=String(raw||'').trim();if(!value)return {error:'и«Ӣе…ҲиІјдёҠ Google Maps з¶ІеқҖгҖӮ'};let url;try{url=new URL(value);}catch{return {error:'йҖҷдёҚжҳҜжңүж•Ҳз¶ІеқҖгҖӮ'};}if(!/(^|\.)google\.|maps\.app\.goo\.gl/.test(url.hostname))return {error:'зӣ®еүҚеҸӘж”ҜжҸҙ Google Maps з¶ІеқҖгҖӮ'};if(url.hostname==='maps.app.goo.gl')return {mapUrl:value,error:'Google зҹӯз¶ІеқҖз„Ўжі•еңЁзҖҸиҰҪеҷЁе…§е…ҚиІ»еұ•й–ӢпјҢи«Ӣж”№иІје®Ңж•ҙз¶ІеқҖгҖӮ'};let lat=null,lng=null,name='';const decoded=decodeURIComponent(url.pathname.replace(/\+/g,' ')),at=decoded.match(/@(-?\d+(?:\.\d+)?),(-?\d+(?:\.\d+)?)/),bang=decoded.match(/!3d(-?\d+(?:\.\d+)?).*?!4d(-?\d+(?:\.\d+)?)/),place=decoded.match(/\/place\/([^/]+)/);if(at){lat=Number(at[1]);lng=Number(at[2]);}else if(bang){lat=Number(bang[1]);lng=Number(bang[2]);}if(place)name=place[1].replace(/\+/g,' ').trim();const query=url.searchParams.get('query')||url.searchParams.get('q')||'';if(!name&&query&&!/^-?\d+(?:\.\d+)?\s*,/.test(query))name=query;const qcoord=query.match(/^(-?\d+(?:\.\d+)?)\s*,\s*(-?\d+(?:\.\d+)?)/);if(qcoord&&lat===null){lat=Number(qcoord[1]);lng=Number(qcoord[2]);}if(!name&&lat===null)return {mapUrl:value,error:'з¶ІеқҖдёӯжІ’жңүеҸҜиҫЁиӯҳзҡ„еә—еҗҚжҲ–еә§жЁҷгҖӮ'};return {mapUrl:value,name,lat,lng};}
function applyGoogleMapsUrl(){const form=$('stopForm'),status=$('mapParseStatus'),result=parseGoogleMapsUrl($('mapUrlInput')?.value);if(!form||!status)return;if(result.error){status.textContent=result.error;status.dataset.tone='error';return;}if(result.name)form.elements.name.value=result.name;if(result.lat!==null&&result.lat!==undefined)form.elements.lat.value=result.lat;if(result.lng!==null&&result.lng!==undefined)form.elements.lng.value=result.lng;updateGooglePlaceLink(form.elements.name.value);status.textContent=`вң“ е·ІеӣһеЎ«${result.name?'еә—еҗҚ':''}${result.lat!==null?'иҲҮеә§жЁҷ':''}`;status.dataset.tone='success';}
function googlePlaceUrl(query=''){return `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent([query,trip().city].filter(Boolean).join(' '))}`;}function updateGooglePlaceLink(query=''){const link=$('googlePlaceSearch');if(link)link.href=googlePlaceUrl(query);}
function openStopSheet(stop=null){const sheet=$('stopSheet'),form=$('stopForm'),moreFields=$('moreFields'),moreSettings=$('moreSettings'),t=trip(),current=day();if(!sheet||!form)return;form.reset();editingStopId=stop?.id||null;$('targetDaySelect').innerHTML=t.days.map((d,i)=>`<option value="${esc(d.id)}">Day ${i+1}пҪң${esc(d.date)} ${esc(d.title)}</option>`).join('');form.elements.targetDay.value=current.id;$('sheetTitle').textContent=stop?'з·ЁијҜжҷҜй»һ':'ж–°еўһжҷҜй»һ';form.querySelector('.sheet-save').textContent=stop?'е„Іеӯҳдҝ®ж”№':'е„ІеӯҳжҷҜй»һ';if(stop)Object.entries(stop).forEach(([key,value])=>{if(form.elements[key])form.elements[key].value=value??'';});if(moreFields)moreFields.hidden=!stop;if(moreSettings)moreSettings.textContent=stop?'ж”¶еҗҲжӣҙеӨҡиЁӯе®ҡвҢғ':'жӣҙеӨҡиЁӯе®ҡвҢ„';clearPlaceResults();updateGooglePlaceLink(stop?.name||'');sheet.hidden=false;sheet.setAttribute('aria-hidden','false');setTimeout(()=>form.elements.name?.focus(),50);}
$('parseMapLink')?.addEventListener('click',applyGoogleMapsUrl);
function closeStopSheet(){const sheet=$('stopSheet');if(!sheet)return;sheet.hidden=true;sheet.setAttribute('aria-hidden','true');editingStopId=null;clearPlaceResults();placeSearchController?.abort();}
function showNotice(message,delay=2800){const bar=$('snackbar');if(!bar)return;clearTimeout(undoTimer);pendingUndo=null;bar.hidden=false;bar.textContent=message;undoTimer=setTimeout(()=>{bar.hidden=true;},delay);}
function deleteStopWithUndo(d,s,index){const t=trip(),key=pkey(d.id,s.id),wasDone=Boolean(t.progress[key]);d.stops.splice(index,1);delete t.progress[key];save();renderDay();clearTimeout(undoTimer);pendingUndo={d,s,index,key,wasDone};const bar=$('snackbar');if(!bar)return;bar.hidden=false;bar.innerHTML=`е·ІеҲӘйҷӨ ${esc(s.name)} <button id="undoDelete">еҫ©еҺҹ</button>`;$('undoDelete')?.addEventListener('click',undoDelete);undoTimer=setTimeout(()=>{bar.hidden=true;pendingUndo=null;},6000);}
function undoDelete(){if(!pendingUndo)return;const {d,s,index,key,wasDone}=pendingUndo;d.stops.splice(index,0,s);if(wasDone)trip().progress[key]=true;save();const bar=$('snackbar');if(bar)bar.hidden=true;clearTimeout(undoTimer);pendingUndo=null;renderDay();}
const stopForm=$('stopForm');if(stopForm)stopForm.onsubmit=e=>{e.preventDefault();const t=trip(),source=day(),f=new FormData(e.currentTarget),raw=Object.fromEntries(f.entries()),target=t.days.find(d=>d.id===raw.targetDay)||source,existing=source.stops.find(s=>s.id===editingStopId);delete raw.targetDay;const stop=normalizeStop({...raw,id:existing?.id||uid('stop')},target.stops.length),moved=target!==source;if(existing){const oldKey=pkey(source.id,existing.id),wasDone=Boolean(t.progress[oldKey]);Object.assign(existing,stop);if(moved){source.stops=source.stops.filter(s=>s!==existing);target.stops.push(existing);delete t.progress[oldKey];if(wasDone)t.progress[pkey(target.id,existing.id)]=true;}}else target.stops.push(stop);sortDay(source);if(moved)sortDay(target);save();closeStopSheet();renderAll();if(moved)showNotice(`е·Іе°ҮгҖҢ${stop.name}гҖҚз§»иҮі Day ${t.days.indexOf(target)+1}`);else setTimeout(()=>document.querySelector(`[data-stop-id="${stop.id}"]`)?.scrollIntoView({behavior:'smooth',block:'center'}),80);};const moreSettings=$('moreSettings');if(moreSettings)moreSettings.onclick=()=>{const more=$('moreFields');if(!more)return;more.hidden=!more.hidden;moreSettings.textContent=more.hidden?'жӣҙеӨҡиЁӯе®ҡвҢ„':'ж”¶еҗҲжӣҙеӨҡиЁӯе®ҡвҢғ';};document.querySelectorAll('[data-close-sheet]').forEach(el=>el.onclick=closeStopSheet);

function clearPlaceResults(message='',retry=false){const box=$('placeResults'),status=$('placeSearchStatus'),button=$('retryPlaceSearch');if(box){box.hidden=true;box.innerHTML='';}if(status)status.textContent=message;if(button)button.hidden=!retry;}
function placeLabel(properties={}){return [properties.name,properties.street,properties.district,properties.city,properties.state,properties.country].filter((v,i,a)=>v&&a.indexOf(v)===i).join(' В· ');}
function guessPlaceType(properties={}){const value=`${properties.osm_value||''} ${properties.type||''}`;if(/restaurant|cafe|fast_food|food/i.test(value))return 'йӨҗйЈІ';if(/hotel|hostel|guest_house/i.test(value))return 'йЈҜеә—';if(/mall|supermarket|department_store|convenience|shop/i.test(value))return 'иіјзү©';if(/station|stop|platform|terminal/i.test(value))return 'дәӨйҖҡ';return 'жҷҜй»һ';}
function searchAlias(query){return /е”җеҗү[и»»иЁ¶]еҫ·|е”җеҗү/i.test(query)?`${query} гғүгғігғ»гӮӯгғӣгғјгғҶ Don Quijote`:query;}
function showPlaceFeatures(features,query){const box=$('placeResults'),status=$('placeSearchStatus');if(!features.length){clearPlaceResults('жүҫдёҚеҲ°зӣёз¬Ұең°й»һпјҢеҸҜж”№з”ЁеӮҷжҸҙжҗңе°ӢгҖӮ',true);return;}box.innerHTML=features.slice(0,5).map((feature,index)=>{const p=feature.properties||{},label=placeLabel(p)||query;return `<button type="button" class="place-result" data-place-index="${index}" role="option"><b>${esc(p.name||query)}</b><small>${esc(label)}</small></button>`;}).join('');box.hidden=false;if(status)status.textContent=`жүҫеҲ° ${Math.min(features.length,5)} еҖӢең°й»һ`;$('retryPlaceSearch').hidden=true;box.querySelectorAll('[data-place-index]').forEach(button=>button.onclick=()=>selectPlace(features[Number(button.dataset.placeIndex)]));}
async function searchPlaces(query){const box=$('placeResults'),status=$('placeSearchStatus'),d=day();if(!box||query.trim().length<2){clearPlaceResults();return;}placeSearchController?.abort();placeSearchController=new AbortController();if(status)status.textContent='жҗңе°ӢдёӯвҖҰ';$('retryPlaceSearch').hidden=true;try{const center=d?.center||[33.5902,130.4017],params=new URLSearchParams({q:`${searchAlias(query.trim())} ${trip().city||''}`,limit:'5',lang:'zh',lat:String(center[0]),lon:String(center[1])});const response=await fetch(`https://photon.komoot.io/api/?${params}`,{signal:placeSearchController.signal});if(!response.ok)throw new Error('search failed');const data=await response.json();showPlaceFeatures(data.features||[],query);}catch(error){if(error.name!=='AbortError')clearPlaceResults('дё»иҰҒжҗңе°Ӣзӣ®еүҚз„Ўжі•йҖЈз·ҡгҖӮ',true);}}
async function fallbackPlaceSearch(query){if(!query||query.trim().length<2)return;const wait=1100-(Date.now()-fallbackSearchAt);if(wait>0)await new Promise(resolve=>setTimeout(resolve,wait));fallbackSearchAt=Date.now();clearPlaceResults('дҪҝз”ЁеӮҷжҸҙжҗңе°ӢдёӯвҖҰ');try{const params=new URLSearchParams({format:'jsonv2',q:`${searchAlias(query.trim())} ${trip().city||''}`,limit:'5',addressdetails:'1','accept-language':'zh-TW',countrycodes:'jp'}),response=await fetch(`https://nominatim.openstreetmap.org/search?${params}`);if(!response.ok)throw new Error('fallback failed');const rows=await response.json(),features=rows.map(row=>({properties:{name:row.name||row.display_name?.split(',')[0],city:row.address?.city||row.address?.town||row.address?.village,state:row.address?.state,country:row.address?.country,osm_value:row.type},geometry:{coordinates:[Number(row.lon),Number(row.lat)]}}));showPlaceFeatures(features,query);}catch{clearPlaceResults('е…©еҖӢжҗңе°ӢдҫҶжәҗйғҪз„Ўжі•йҖЈз·ҡпјҢи«Ӣе…ҲжүӢеӢ•ијёе…ҘгҖӮ',true);}}
function selectPlace(feature){const form=$('stopForm'),p=feature.properties||{},coordinates=feature.geometry?.coordinates||[];if(!form)return;form.elements.name.value=p.name||form.elements.name.value;form.elements.lat.value=coordinates[1]??'';form.elements.lng.value=coordinates[0]??'';form.elements.type.value=guessPlaceType(p);if(!form.elements.note.value)form.elements.note.value=placeLabel(p);clearPlaceResults('вң“ е·Іеё¶е…Ҙең°еқҖиҲҮеә§жЁҷ');}
const placeSearchInput=$('placeSearchInput');if(placeSearchInput)placeSearchInput.addEventListener('input',event=>{clearTimeout(placeSearchTimer);const query=event.target.value;updateGooglePlaceLink(query);placeSearchTimer=setTimeout(()=>searchPlaces(query),450);});$('retryPlaceSearch')?.addEventListener('click',()=>fallbackPlaceSearch($('placeSearchInput')?.value||''));

let wizardStep=0;
function setWizardStep(step){wizardStep=Math.max(0,Math.min(2,step));document.querySelectorAll('[data-wizard-step]').forEach(el=>el.hidden=Number(el.dataset.wizardStep)!==wizardStep);$('wizardProgress').textContent=`жӯҘй©ҹ ${wizardStep+1}пјҸ3`;$('wizardBack').hidden=wizardStep===0;$('wizardNext').hidden=wizardStep===2;$('wizardCreate').hidden=wizardStep!==2;}
function openTripWizard(){const modal=$('tripWizard'),form=$('tripWizardForm');form.reset();const start=new Date();start.setDate(start.getDate()+1);form.elements.startDate.value=start.toISOString().slice(0,10);form.elements.endDate.value=form.elements.startDate.value;setWizardStep(0);modal.hidden=false;modal.setAttribute('aria-hidden','false');setTimeout(()=>form.elements.title.focus(),50);}
function closeTripWizard(){const modal=$('tripWizard');modal.hidden=true;modal.setAttribute('aria-hidden','true');}
function wizardDays(startValue,endValue){const start=new Date(`${startValue}T12:00:00`),end=new Date(`${endValue}T12:00:00`),count=Math.floor((end-start)/86400000)+1;if(!Number.isFinite(count)||count<1||count>31)throw new Error('ж—ҘжңҹйңҖзӮә 1пҪһ31 еӨ©гҖӮ');return Array.from({length:count},(_,i)=>{const date=new Date(start);date.setDate(date.getDate()+i);return normalizeDay({id:uid('day'),date:`${date.getMonth()+1}/${date.getDate()}`,title:`з¬¬ ${i+1} еӨ©`,theme:'й»һж“Ҡж–°еўһжҷҜй»һй–Ӣе§Ӣе®үжҺ’гҖӮ',stops:[]},i);});}
function createTrip(){openTripWizard();}
$('wizardNext')?.addEventListener('click',()=>{const form=$('tripWizardForm'),step=document.querySelector(`[data-wizard-step="${wizardStep}"]`);if(![...step.querySelectorAll('input')].every(input=>input.reportValidity()))return;if(wizardStep===1&&form.elements.endDate.value<form.elements.startDate.value)return alert('зөҗжқҹж—ҘжңҹдёҚиғҪж—©ж–јй–Ӣе§Ӣж—ҘжңҹгҖӮ');setWizardStep(wizardStep+1);});
$('wizardBack')?.addEventListener('click',()=>setWizardStep(wizardStep-1));document.querySelectorAll('[data-close-wizard]').forEach(el=>el.addEventListener('click',closeTripWizard));
$('tripWizardForm')?.addEventListener('submit',event=>{event.preventDefault();const form=event.currentTarget,data=Object.fromEntries(new FormData(form).entries());let days;try{days=wizardDays(data.startDate,data.endDate);}catch(error){return alert(error.message);}const start=new Date(`${data.startDate}T12:00:00`),end=new Date(`${data.endDate}T12:00:00`),nights=Math.max(0,Math.round((end-start)/86400000));const t=normalizeTrip({id:uid('trip'),title:data.title,brandLine:`${data.city.toUpperCase()} TRIP`,subtitle:data.members||'иҮӘз”ұиҰҸеҠғж—…иЎҢ',members:data.members,city:data.city,startDate:data.startDate,dateRange:`${start.getMonth()+1}/${start.getDate()}вҖ“${end.getMonth()+1}/${end.getDate()}`,hotel:data.hotel,nights:`${nights} жҷҡ`,themeColor:'#173f73',days,progress:{},currentDayId:days[0].id});appData.trips.push(t);appData.currentTripId=t.id;save();closeTripWizard();switchView('scheduleView');renderAll();setAppStatus('вң“ ж–°ж—…иЎҢе·Іе»әз«Ӣ','saved',2600);});
function copyTrip(){const t=clone(trip());t.id=uid('trip');t.templateKey='';t.title=`${t.title} еүҜжң¬`;t.progress={};t.coverPhoto='';t.days=t.days.map(d=>({...d,id:uid('day'),stops:d.stops.map(s=>({...s,id:uid('stop')}))}));t.currentDayId=t.days[0]?.id;appData.trips.push(t);appData.currentTripId=t.id;save();renderAll();}
function deleteTrip(){if(appData.trips.length<=1)return alert('иҮіе°‘йңҖдҝқз•ҷдёҖеҖӢж—…иЎҢгҖӮ');const target=trip(),name=target.title.replace(/\n/g,' ');if(confirm(`зўәе®ҡеҲӘйҷӨгҖҢ${name}гҖҚпјҹ\n\nжӯӨж—…зЁӢзҡ„иЎҢзЁӢгҖҒз…§зүҮиҲҮе®ҢжҲҗзҙҖйҢ„йғҪжңғеҫһйҖҷж”ҜжүӢж©ҹз§»йҷӨгҖӮ`)){appData.trips=appData.trips.filter(t=>t.id!==target.id);appData.currentTripId=appData.trips[0].id;save();switchView('homeView');renderAll();setAppStatus('вң“ ж—…зЁӢе·ІеҲӘйҷӨ','saved',2600);}}
function downloadJson(name,data){const a=document.createElement('a'),url=URL.createObjectURL(new Blob([JSON.stringify(data,null,2)],{type:'application/json'}));a.href=url;a.download=name;a.click();URL.revokeObjectURL(url);}
function performFullBackup(){downloadJson('tino-travel-v4-backup.json',{...clone(appData),exportedAt:new Date().toISOString()});lastBackupAt=Date.now();localStorage.setItem(BACKUP_KEY,String(lastBackupAt));setAppStatus('вң“ е®Ңж•ҙеӮҷд»Ҫе·ІдёӢијү','saved',3000);renderHome();renderSettings();}
function validateTrip(raw){if(!raw||typeof raw!=='object')return 'JSON еҝ…й ҲжҳҜж—…иЎҢзү©д»¶гҖӮ';const ds=raw.days||raw.itinerary;if(!Array.isArray(ds)||!ds.length)return 'ж—…иЎҢеҝ…й ҲеҢ…еҗ« days йҷЈеҲ—гҖӮ';for(const [di,d] of ds.entries()){if(!Array.isArray(d.stops))return `з¬¬ ${di+1} еӨ©зјәе°‘ stops йҷЈеҲ—гҖӮ`;for(const [si,s] of d.stops.entries()){if(s.lat!==''||s.lng!==''){const lat=Number(s.lat),lng=Number(s.lng);if(!Number.isFinite(lat)||lat<-90||lat>90||!Number.isFinite(lng)||lng<-180||lng>180)return `з¬¬ ${di+1} еӨ©з¬¬ ${si+1} з«ҷеә§жЁҷз„Ўж•ҲгҖӮ`;}}}return '';}
function importJson(file){if(!file)return;const r=new FileReader();r.onload=()=>{const raw=safeJson(r.result,null);if(!raw)return alert('еҢҜе…ҘеӨұж•—пјҡJSON и§ЈжһҗеӨұж•—пјҢзҸҫжңүиіҮж–ҷжңӘиҰҶи“ӢгҖӮ');if(raw.schemaVersion===SCHEMA_VERSION&&Array.isArray(raw.trips))return alert('йҖҷжҳҜе®Ңж•ҙеӮҷд»ҪжӘ”пјҢи«Ӣж”№з”ЁгҖҢе®Ңж•ҙйӮ„еҺҹгҖҚй җиҰҪеҫҢеҶҚиҷ•зҗҶгҖӮ');const err=validateTrip(raw);if(err)return alert(`еҢҜе…ҘеӨұж•—пјҡ${err} зҸҫжңүиіҮж–ҷжңӘиҰҶи“ӢгҖӮ`);const t=normalizeTrip(raw);t.id=uid('trip');t.days=t.days.map(d=>({...d,id:uid('day'),stops:d.stops.map(s=>({...s,id:uid('stop')}))}));t.currentDayId=t.days[0].id;appData.trips.push(t);appData.currentTripId=t.id;save();renderAll();alert('ж—…иЎҢеҢҜе…Ҙе®ҢжҲҗгҖӮ');};r.readAsText(file);}

function validateBackup(raw){if(!raw||raw.schemaVersion!==SCHEMA_VERSION||!Array.isArray(raw.trips)||!raw.trips.length)return 'йҖҷдёҚжҳҜеҸҜз”Ёзҡ„е®Ңж•ҙж—…иЎҢеӮҷд»ҪгҖӮ';for(const [i,t] of raw.trips.entries()){const error=validateTrip(t);if(error)return `з¬¬ ${i+1} и¶ҹж—…иЎҢиіҮж–ҷжңүиӘӨпјҡ${error}`;}return '';}
function backupPreview(raw,file){const trips=raw.trips.length,days=raw.trips.reduce((n,t)=>n+(t.days||t.itinerary||[]).length,0),stops=raw.trips.reduce((n,t)=>n+(t.days||t.itinerary||[]).reduce((m,d)=>m+(d.stops||[]).length,0),0),photos=raw.trips.filter(t=>t.coverPhoto).length,date=new Date(raw.exportedAt||file.lastModified);return {trips,days,stops,photos,date:Number.isNaN(date.getTime())?'жңӘиЁҳйҢ„':date.toLocaleString('zh-TW')};}
function openRestorePreview(raw,file){const preview=backupPreview(raw,file),sheet=$('restoreSheet');pendingRestore={raw,file};$('restorePreview').innerHTML=`<div class="restore-date"><span>еӮҷд»ҪжҷӮй–“</span><b>${esc(preview.date)}</b></div><div class="restore-counts"><span><b>${preview.trips}</b> и¶ҹж—…иЎҢ</span><span><b>${preview.days}</b> еӨ©</span><span><b>${preview.stops}</b> еҖӢжҷҜй»һ</span><span><b>${preview.photos}</b> ејөдё»з…§зүҮ</span></div>`;sheet.hidden=false;sheet.setAttribute('aria-hidden','false');}
function closeRestorePreview(){const sheet=$('restoreSheet');sheet.hidden=true;sheet.setAttribute('aria-hidden','true');pendingRestore=null;}
function readFullBackup(file){if(!file)return;const r=new FileReader();r.onload=()=>{const raw=safeJson(r.result,null),error=validateBackup(raw);if(error)return alert(`${error} зӣ®еүҚиіҮж–ҷе®Ңе…ЁжІ’жңүи®ҠжӣҙгҖӮ`);openRestorePreview(raw,file);};r.onerror=()=>alert('еӮҷд»ҪжӘ”з„Ўжі•и®ҖеҸ–пјҢзӣ®еүҚиіҮж–ҷе®Ңе…ЁжІ’жңүи®ҠжӣҙгҖӮ');r.readAsText(file);}
function remapImportedTrip(raw){const t=normalizeTrip(raw),oldTripId=t.id,oldProgress=t.progress||{},newProgress={},dayMap=new Map();t.id=uid('trip');t.days=t.days.map(d=>{const oldDayId=d.id,newDayId=uid('day'),stops=d.stops.map(s=>{const oldStopId=s.id,newStopId=uid('stop');if(oldProgress[`${oldTripId}:${oldDayId}:${oldStopId}`])newProgress[`${t.id}:${newDayId}:${newStopId}`]=true;return {...s,id:newStopId};});dayMap.set(String(oldDayId),newDayId);return {...d,id:newDayId,stops};});t.currentDayId=dayMap.get(String(t.currentDayId))||t.days[0]?.id;t.progress=newProgress;return t;}
function applyFullRestore(mode){if(!pendingRestore)return;const before=appData,raw=pendingRestore.raw;if(mode==='replace')appData=normalizeAppData(raw);else{const imported=raw.trips.map(remapImportedTrip);appData=normalizeAppData({schemaVersion:SCHEMA_VERSION,currentTripId:imported[0].id,trips:[...appData.trips,...imported]});}if(!save()){appData=before;return;}closeRestorePreview();renderAll();switchView('homeView');setAppStatus(mode==='replace'?'вң“ е®Ңж•ҙиіҮж–ҷе·ІйӮ„еҺҹ':'вң“ еӮҷд»Ҫж—…иЎҢе·ІеҗҲдҪө','saved',3200);}
$('mergeRestore')?.addEventListener('click',()=>applyFullRestore('merge'));$('replaceRestore')?.addEventListener('click',()=>{if(confirm('зўәе®ҡз”ЁйҖҷд»ҪеӮҷд»ҪеҸ–д»Јзӣ®еүҚжүҖжңүж—…иЎҢпјҹ'))applyFullRestore('replace');});document.querySelectorAll('[data-close-restore]').forEach(el=>el.addEventListener('click',closeRestorePreview));

function compressCoverPhoto(file){return new Promise((resolve,reject)=>{if(!file?.type.startsWith('image/'))return reject(new Error('и«ӢйҒёж“Үз…§зүҮжӘ”жЎҲгҖӮ'));const image=new Image(),url=URL.createObjectURL(file);image.onload=()=>{const max=1280,scale=Math.min(1,max/Math.max(image.naturalWidth,image.naturalHeight)),canvas=document.createElement('canvas');canvas.width=Math.max(1,Math.round(image.naturalWidth*scale));canvas.height=Math.max(1,Math.round(image.naturalHeight*scale));canvas.getContext('2d').drawImage(image,0,0,canvas.width,canvas.height);URL.revokeObjectURL(url);resolve(canvas.toDataURL('image/jpeg',.78));};image.onerror=()=>{URL.revokeObjectURL(url);reject(new Error('з…§зүҮз„Ўжі•и®ҖеҸ–пјҢи«Ӣж”№йҒё JPGгҖҒPNG жҲ– WebPгҖӮ'));};image.src=url;});}
async function setCoverPhoto(file){if(!file)return;const t=trip(),previous=t.coverPhoto;setAppStatus('з…§зүҮиҷ•зҗҶдёӯвҖҰ','update',0);try{t.coverPhoto=await compressCoverPhoto(file);if(!save()){t.coverPhoto=previous;return;}renderHome();setAppStatus('вң“ ж—…иЎҢз…§зүҮе·Іе„Іеӯҳ','saved',2600);}catch(error){t.coverPhoto=previous;setAppStatus('з…§зүҮеҠ е…ҘеӨұж•—','error',2600);alert(error.message);}}

function tripDayISO(t,d){if(!/^\d{4}-\d{2}-\d{2}$/.test(t.startDate||''))return '';const index=t.days.indexOf(d),date=new Date(`${t.startDate}T12:00:00`);date.setDate(date.getDate()+Math.max(0,index));return date.toISOString().slice(0,10);}
function weatherText(code){if(code===0)return 'жҷҙжң—';if([1,2].includes(code))return 'жҷҙжҷӮеӨҡйӣІ';if(code===3)return 'йҷ°еӨ©';if([45,48].includes(code))return 'жңүйң§';if(code>=51&&code<=67)return 'дёӢйӣЁ';if(code>=71&&code<=77)return 'йҷҚйӣӘ';if(code>=80&&code<=82)return 'йҷЈйӣЁ';if(code>=95)return 'йӣ·йӣЁ';return 'еӨ©ж°Ји®ҠеҢ–';}
function renderWeather(){const t=trip(),d=day(),iso=tripDayISO(t,d),box=$('dayWeather'),record=weatherCache[t.id]?.days?.[iso];if(!box)return;if(record){box.innerHTML=`<span>рҹҢЎ ${Math.round(record.min)}вҖ“${Math.round(record.max)}В°C</span><span>вҳ” йҷҚйӣЁ ${Math.round(record.rain)}%</span><span>${esc(weatherText(record.code))}</span>`;return;}const available=iso?new Date(`${iso}T12:00:00`):null;if(available)available.setDate(available.getDate()-15);const availableText=available?`${available.getMonth()+1}/${available.getDate()} иө·еҸҜжҹҘзңӢжӯӨж—Ҙй җе ұ`:'и«ӢеңЁиЁӯе®ҡеЎ«еҜ«ж—…иЎҢй–Ӣе§Ӣж—Ҙ';box.innerHTML=`<span>рҹҢӨ ${availableText}</span><button type="button" id="refreshWeather">жӣҙж–°</button>`;$('refreshWeather')?.addEventListener('click',()=>refreshWeather(true));}
async function refreshWeather(force=false){const t=trip(),cache=weatherCache[t.id],fresh=cache&&Date.now()-cache.fetchedAt<30*60*1000;if(fresh&&!force){renderWeather();return;}if(weatherRequest)return;const centers=t.days.map(d=>d.center).filter(c=>Array.isArray(c)),lat=centers.length?centers.reduce((n,c)=>n+num(c[0]),0)/centers.length:33.5902,lng=centers.length?centers.reduce((n,c)=>n+num(c[1]),0)/centers.length:130.4017;weatherRequest=fetch(`https://api.open-meteo.com/v1/forecast?latitude=${lat}&longitude=${lng}&daily=weather_code,temperature_2m_max,temperature_2m_min,precipitation_probability_max&timezone=Asia%2FTokyo&forecast_days=16`).then(r=>{if(!r.ok)throw new Error('weather');return r.json();}).then(data=>{const daily=data.daily||{},days={};(daily.time||[]).forEach((date,i)=>days[date]={code:num(daily.weather_code?.[i]),max:num(daily.temperature_2m_max?.[i]),min:num(daily.temperature_2m_min?.[i]),rain:num(daily.precipitation_probability_max?.[i])});weatherCache[t.id]={fetchedAt:Date.now(),days};localStorage.setItem(WEATHER_KEY,JSON.stringify(weatherCache));}).catch(()=>{}).finally(()=>{weatherRequest=null;renderWeather();});}

function setEditMode(value){editMode=Boolean(value);localStorage.setItem(EDIT_KEY,String(editMode));$('editToggle').textContent=editMode?'е®ҢжҲҗз·ЁијҜ':'з·ЁијҜжЁЎејҸ';renderAll();}
function offerAppUpdate(worker){if(!worker)return;pendingWorker=worker;$('updateApp').hidden=false;setAppStatus('вҶ‘ жңүж–°зүҲ','update',0);}
function applyAppUpdate(){if(!pendingWorker)return;$('updateApp').disabled=true;$('updateApp').textContent='жӣҙж–°дёӯвҖҰ';setAppStatus('жӯЈеңЁжӣҙж–°вҖҰ','update',0);pendingWorker.postMessage({type:'SKIP_WAITING'});}
function registerAppWorker(){if(!('serviceWorker'in navigator))return;addEventListener('load',()=>navigator.serviceWorker.register('./sw.js').then(reg=>{if(reg.waiting)offerAppUpdate(reg.waiting);reg.addEventListener('updatefound',()=>{const worker=reg.installing;worker?.addEventListener('statechange',()=>{if(worker.state==='installed'&&navigator.serviceWorker.controller)offerAppUpdate(worker);});});reg.update().catch(()=>{});}).catch(()=>setAppStatus('йӣўз·ҡеҠҹиғҪиЁӯе®ҡеӨұж•—','error',0)));navigator.serviceWorker.addEventListener('controllerchange',()=>{if(updateReloading)return;updateReloading=true;location.reload();});}
function switchView(id){if(id!=='homeView'&&editMode)setEditMode(false);document.querySelectorAll('.nav-item').forEach(b=>b.classList.toggle('active',b.dataset.view===id));document.querySelectorAll('.view').forEach(v=>v.classList.toggle('active',v.id===id));$('hero')?.classList.toggle('hidden',id!=='homeView');const main=document.querySelector('.app-shell>main');if(main)main.scrollTo({top:0,behavior:'auto'});window.scrollTo({top:0,behavior:'auto'});if(id==='mapView'){renderMapTabs();fitMap(day(),showAllMap);}}
function initMap(){if(!window.L){$('mapFallback').hidden=false;return;}map=L.map('map',{zoomControl:false}).setView([33.5902,130.4017],13);L.control.zoom({position:'bottomright'}).addTo(map);L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png',{maxZoom:19,attribution:'В© OpenStreetMap contributors'}).addTo(map);}
function updateMap(d=day(),all=showAllMap){if(!map)return;markers.forEach(m=>map.removeLayer(m));markers=[];routeLines.forEach(line=>map.removeLayer(line));routeLines=[];const t=trip(),days=all?t.days:[d];days.forEach(td=>{const dayIndex=t.days.indexOf(td),color=MAP_COLORS[dayIndex%MAP_COLORS.length],pts=td.stops.filter(hasCoord).map(s=>{const stopIndex=td.stops.indexOf(s)+1,label=all?`${dayIndex+1}.${stopIndex}`:stopIndex,size=all?36:30,icon=L.divIcon({className:'',html:`<div class="number-marker ${all?'all':''}" style="background:${color}">${label}</div>`,iconSize:[size,30],iconAnchor:[size/2,15]});markers.push(L.marker([s.lat,s.lng],{icon}).addTo(map).bindPopup(`<strong>Day ${dayIndex+1} В· ${esc(s.time)}пҪң${esc(s.name)}</strong><br>${esc(s.note)}`));return [s.lat,s.lng];});if(pts.length>1)routeLines.push(L.polyline(pts,{color,weight:4,dashArray:'7 9',opacity:.82}).addTo(map));});fitMap(d,all);}
function fitMap(d=day(),all=showAllMap){const days=all?trip().days:[d],pts=days.flatMap(td=>(td?.stops||[]).filter(hasCoord).map(s=>[Number(s.lat),Number(s.lng)]));if(!map||!pts.length)return false;setTimeout(()=>{map.invalidateSize();if(pts.length===1)map.setView(pts[0],15);else map.fitBounds(L.latLngBounds(pts).pad(.14));},100);return true;}
addEventListener('online',()=>setAppStatus('вң“ е·ІйҖЈз·ҡ','saved'));addEventListener('offline',()=>setAppStatus('в—Ҹ йӣўз·ҡдҪҝз”Ёдёӯ','offline',0));if(!navigator.onLine)setTimeout(()=>setAppStatus('в—Ҹ йӣўз·ҡдҪҝз”Ёдёӯ','offline',0),0);
document.querySelectorAll('.nav-item').forEach(b=>b.onclick=()=>switchView(b.dataset.view));$('tripSelect').onchange=e=>{appData.currentTripId=e.target.value;showAllMap=false;save();renderAll();};$('newTrip').onclick=createTrip;$('copyTrip').onclick=copyTrip;$('editToggle').onclick=()=>setEditMode(!editMode);$('updateApp').onclick=applyAppUpdate;$('fitMap').onclick=()=>{showAllMap=true;updateMap(day(),true);renderMapTabs();};$('importFile').onchange=e=>{importJson(e.target.files[0]);e.target.value='';};$('restoreFile').onchange=e=>{readFullBackup(e.target.files[0]);e.target.value='';};$('coverPhotoInput').onchange=e=>{setCoverPhoto(e.target.files[0]);e.target.value='';};addEventListener('beforeinstallprompt',e=>{e.preventDefault();deferredPrompt=e;$('installBtn').hidden=false;});$('installBtn').onclick=async()=>{if(!deferredPrompt)return;deferredPrompt.prompt();await deferredPrompt.userChoice;deferredPrompt=null;$('installBtn').hidden=true;};registerAppWorker();document.body.insertAdjacentHTML('beforeend','<datalist id="typeList"><option value="жҺҘйҖҒ"><option value="йЈҜеә—"><option value="йӨҗйЈІ"><option value="иҰӘеӯҗ"><option value="дј‘жҒҜ"><option value="жҷҜй»һ"><option value="ең°йҗө"><option value="иҪүд№ҳ"><option value="JR"><option value="дәӨйҖҡ"><option value="иіјзү©"><option value="жӢҚз…§"><option value="еҢ…и»Ҡ"><option value="ж©ҹе ҙ"><option value="иҲӘзҸӯ"><option value="еӮҷжЎҲ"></datalist>');$('editToggle').textContent=editMode?'е®ҢжҲҗз·ЁијҜ':'з·ЁијҜжЁЎејҸ';initMap();renderAll();
